    restart: unless-stopped
    ports:
      - "6379:6379"
    networks:
      - pdv-net

  nginx:
    image: nginx:alpine
    container_name: pdv_nginx
    restart: unless-stopped
    ports:
      - "80:80"
      - "443:443"
    volumes:
      - ../:/var/www
      - ./nginx.conf:/etc/nginx/conf.d/default.conf:ro
      - ./ssl:/etc/nginx/ssl:ro
    depends_on:
      - pdv-app
    networks:
      - pdv-net

volumes:
  mysql_

networks:
  pdv-net:
    driver: bridge
```

